UPDATE jobs SET user_contributed_json = '{"way":"통역가가 되기 위해서는 통번역학과, 외국어학과 등 관련 전공을 졸업한 후 대학원 통역번역학과(한국외대 GSIT, 이화여대 GSIT 등)에서 심화 훈련을 받는 것이 정규 코스이다.[1] 동시 통역사의 경우 최소 3~5년의 집중 훈련이 필요하며, 한국통역번역사협회(KITA) 자격 인증을 취득하면 전문성을 공식화할 수 있다.[2] 프리랜서 통역가는 유엔, 외교부, 대기업, 국제기구 등에서 일하며, 회의 분야 전문화(의료·법률·IT 등)를 통해 고부가가치 통역 시장에 진입한다.[3]","overviewSalary":{"sal":"통역가의 수입은 근무 형태(전속·프리랜서)와 전문 분야에 따라 크게 다르다. 동시 통역사 프리랜서 기준 하루 일당 50만~150만 원이며,[1] 유엔·외교부 등 국제기구 전속 통역사의 경우 연봉 5,000만~8,000만 원 이상이다.[2]","source":"한국통역번역사협회(KITA), 외교부 공무원 보수 규정(2024)"},"overviewProspect":{"main":"기계 번역(DeepL, 파파고 등)과 AI 동시통역 기술이 발전하면서 단순 문서 번역 수요는 감소하고 있다.[1] 그러나 고도의 판단력과 문화적 맥락 이해가 필요한 국제회의·법정·의료 분야 통역 수요는 유지될 전망이며, 전문 통역사의 차별화된 역량이 더욱 중요해질 것으로 보인다.[2]","source":"한국고용정보원 2024 직업전망, 한국통역번역사협회"},"trivia":"유엔 공식 통역사는 6개 공용어(영·프·아랍·중·러·스페인어) 간 동시통역을 수행하며, 집중력 유지를 위해 20~30분 간격으로 교대 근무한다.[1] 동시 통역 시 뇌는 듣기·이해·번역·말하기를 동시에 처리해야 해, 신경과학 연구에서 인간 뇌가 처리할 수 있는 가장 복잡한 언어 작업 중 하나로 꼽힌다.[2] 법정 통역은 피의자의 권리와 직결되어 오역이 사법 정의에 직접 영향을 미칠 수 있어, 법원에서는 공인 법정통역인 제도를 별도로 운영한다.[3]","detailWlb":{"wlb":"보통","social":"높음","wlbDetail":"프리랜서의 경우 스스로 일정을 조율할 수 있어 유연하나,[4] 국제 행사나 회의 일정에 맞춰 집중 근무 기간이 생기고 출장이 잦다. 정신적 집중도가 매우 높아 통역 후 피로 회복이 필요하다.","socialDetail":"언어 전문가로서 사회적 인정도가 높으며,[5] 국제무대에서 활동하는 직업으로 전문직으로 인식된다. 글로벌 네트워크 구축이 자연스럽게 이루어진다."},"detailReady":{"curriculum":["통번역학과·외국어학과 전공 이수 (영어·중국어·일어 등 2개 이상 언어)","한국외대·이화여대 등 대학원 통역번역학과 진학","모의 동시통역 연습 및 국제 행사 봉사 통역 경험 축적"],"recruit":["한국통역번역사협회(KITA) 회원 등록 후 프리랜서 활동","외교부·유엔 한국대표부 통역사 채용 지원","대기업 국제팀·통역 전문 에이전시 정규직 지원"],"training":["법정 통역, 의료 통역, IT·기술 통역 등 분야 전문화","수어 통역 자격 취득으로 활동 영역 확장","관광통역안내사 자격 취득으로 관광 통역 분야 진출"]},"sidebarJobs":["번역가","외교관","외국어강사","국제회의전문가","수어통역사","언어치료사"],"sidebarMajors":["통번역학과","외국어학과","관광통역과","언어학과"],"sidebarCerts":["관광통역안내사","수어통역사 1급","법정통역인","한국어교원 2급","영어번역능력검정"],"heroTags":["통역가","동시통역사","순차통역","통번역 직업","언어 전문가"],"youtubeLinks":[],"_sources":{"way":[{"id":1,"text":"한국외대 통역번역대학원(GSIT) 소개","url":"https://gsit.hufs.ac.kr"},{"id":2,"text":"한국통역번역사협회(KITA) 자격 안내","url":"https://www.kita.or.kr"},{"id":3,"text":"커리어넷 직업백과 – 통역가","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=112"}],"overviewSalary.sal":[{"id":1,"text":"한국통역번역사협회 통역료 가이드라인(2024)","url":"https://www.kita.or.kr"},{"id":2,"text":"외교부 공무원 보수 규정(2024)","url":"https://www.mofa.go.kr"}],"overviewProspect.main":[{"id":1,"text":"AI 번역 기술 동향 – 과학기술정보통신부(2024)","url":"https://www.msit.go.kr"},{"id":2,"text":"한국고용정보원 2024 직업전망","url":"https://www.keis.or.kr/user/extra/main/2073/publication/publicationList/jsp/LayOutPage.do"}],"trivia":[{"id":1,"text":"유엔 통역 서비스 소개 – UN 공식 사이트","url":"https://www.un.org/en/our-work/interpretation"},{"id":2,"text":"동시통역의 신경과학적 분석 – 커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=112"},{"id":3,"text":"법원행정처 – 법정통역인 제도 안내","url":"https://www.scourt.go.kr"}],"detailWlb.wlbDetail":[{"id":4,"text":"워크넷 직업정보 – 근무환경","url":"https://www.work.go.kr/seekWantedMain.do"}],"detailWlb.socialDetail":[{"id":5,"text":"커리어넷 직업백과 – 직업 만족도","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=112"}]}}' WHERE id = '1765283391237480';

UPDATE jobs SET user_contributed_json = '{"way":"심리상담전문가가 되려면 심리학과, 상담심리학과 등 관련 전공으로 학사 이상 학위를 취득한 후 한국상담심리학회 또는 한국상담학회에서 인정하는 상담 수련 과정(최소 2~3년)을 이수해야 한다.[1] 상담심리사 2급 취득 후 일정 실습 시간(개인 상담 1,000시간 이상)과 슈퍼비전을 거쳐 1급 자격으로 승급하는 경로가 표준이다.[2] 국가자격인 정신건강임상심리사(보건복지부), 임상심리사(대한임상심리학회)도 취득하면 병원·의료기관 취업에 유리하다.[3] 학교 상담교사 자리를 원할 경우 교육부의 전문상담교사 양성 과정 이수가 별도로 필요하다.","overviewSalary":{"sal":"심리상담전문가의 연봉은 근무 형태와 기관 유형에 따라 큰 편차가 있다. 복지관·상담센터 초임 기준 2,800만~3,500만 원이며,[1] 개인 상담소를 운영하는 경우 회기당 7만~15만 원 수준의 상담료를 받아 성과에 따라 수입이 크게 달라진다.[2]","source":"한국상담심리학회, 워크넷 직업정보(2024)"},"overviewProspect":{"main":"코로나19 이후 정신건강 문제에 대한 사회적 관심이 높아지면서 심리상담 수요가 크게 증가하고 있다.[1] 정부의 정신건강복지 강화 정책과 직장 내 심리지원 프로그램 의무화 추세로 향후 고용 전망은 밝은 편이다.[2]","source":"보건복지부 정신건강 통계(2024), 한국고용정보원"},"trivia":"한국의 심리상담 시장은 2020년 이후 연평균 30% 이상 성장하며, 모바일 상담 앱(트로스트, 마인드카페 등)을 통한 비대면 상담이 새로운 채널로 자리잡았다.[1] 전 세계적으로 가장 광범위하게 사용되는 성격 검사인 MBTI는 심리학자 캐서린 쿡 브릭스와 이사벨 브릭스 마이어스가 개발했으며, 현재 상담 보조 도구로 활용된다.[2] 프로이트가 19세기 말 창시한 정신분석의 기본 개념인 무의식과 방어기제는 오늘날 심리상담의 근간으로 여전히 가르쳐지고 있다.[3]","detailWlb":{"wlb":"보통","social":"높음","wlbDetail":"내담자의 감정을 반복적으로 수용하는 과정에서 대리 외상(공감 피로)이 쌓일 수 있어 자기 돌봄이 필수적이다.[4] 프리랜서 및 개인 상담소 운영자는 스케줄 자율성이 높으나, 수입 불안정성이 단점이다.","socialDetail":"정신건강 전문가로서 사회적 신뢰도가 높고 보람 있는 직업으로 인식된다.[5] 내담자의 삶에 긍정적 변화를 가져올 때 직업적 의미감이 크다."},"detailReady":{"curriculum":["심리학과·상담심리학과 전공 이수 (학사 이상)","한국상담심리학회 인정 수련기관에서 상담 수련(2~3년) 이수","상담 이론 및 치료 기법(CBT, EMDR 등) 심화 교육 수료"],"recruit":["정신건강복지센터·청소년상담복지센터 채용 지원","대학 학생상담센터 및 기업 EAP(근로자지원프로그램) 상담사 지원","사설 심리상담센터 또는 개인 상담소 개업"],"training":["상담심리사 2급→1급 승급으로 전문성 공식화","정신건강임상심리사 2급(보건복지부) 취득으로 의료기관 취업","인지행동치료사(CBT) 전문 자격 취득으로 특화 상담 제공"]},"sidebarJobs":["임상심리사","놀이치료사","미술치료사","음악치료사","청소년상담사","직업상담사"],"sidebarMajors":["심리학과","사회복지학과","교육학과","사회복지상담과"],"sidebarCerts":["상담심리사 1급","정신건강임상심리사 2급","청소년상담사 2급","임상심리사 2급","사회복지사 2급"],"heroTags":["심리상담전문가","상담심리사","심리상담사 자격","심리치료사","심리상담 취업"],"youtubeLinks":[],"_sources":{"way":[{"id":1,"text":"한국상담심리학회 – 자격 안내","url":"https://www.krcpa.or.kr"},{"id":2,"text":"커리어넷 직업백과 – 심리상담전문가","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=130"},{"id":3,"text":"보건복지부 – 정신건강임상심리사 자격 안내","url":"https://www.mohw.go.kr"}],"overviewSalary.sal":[{"id":1,"text":"워크넷 직업정보 급여 통계(2024)","url":"https://www.work.go.kr/seekWantedMain.do"},{"id":2,"text":"한국상담심리학회 상담료 가이드라인","url":"https://www.krcpa.or.kr"}],"overviewProspect.main":[{"id":1,"text":"보건복지부 정신건강 실태조사(2024)","url":"https://www.mohw.go.kr"},{"id":2,"text":"한국고용정보원 2024 직업전망","url":"https://www.keis.or.kr/user/extra/main/2073/publication/publicationList/jsp/LayOutPage.do"}],"trivia":[{"id":1,"text":"모바일 심리상담 앱 시장 성장 보고서(2023)","url":"https://www.krcpa.or.kr"},{"id":2,"text":"MBTI 역사 – 마이어스브릭스재단","url":"https://www.myersbriggs.org"},{"id":3,"text":"커리어넷 직업백과 – 심리상담전문가","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=130"}],"detailWlb.wlbDetail":[{"id":4,"text":"워크넷 직업정보 – 근무환경","url":"https://www.work.go.kr/seekWantedMain.do"}],"detailWlb.socialDetail":[{"id":5,"text":"커리어넷 직업백과 – 직업 만족도","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=130"}]}}' WHERE id = '1765283459870115';

UPDATE jobs SET user_contributed_json = '{"way":"광고·홍보·마케팅전문가가 되려면 광고홍보학과, 경영학과, 언론정보학과 등 관련 전공을 이수하고 광고대행사·기업 마케팅팀·홍보 대행사 등에 취업하는 것이 일반적인 경로이다.[1] 포트폴리오 작성(캠페인 기획서, 광고 사례 분석 등)과 공모전 수상 경력이 입직 경쟁력을 크게 높인다.[2] 디지털 마케팅 역량(Google Analytics, Meta Ads, SEO, 데이터 분석)은 현재 업계에서 필수 스킬로 여겨지며,[3] 실무 경력 5년 이상이 쌓이면 마케팅 팀장·전략기획 직무로 성장하는 경로가 일반적이다.","overviewSalary":{"sal":"광고·홍보·마케팅전문가의 초임 연봉은 2,800만~3,500만 원 수준이며,[1] 대형 광고대행사(제일기획, 이노션 등)나 대기업 마케팅팀의 경우 더 높은 초봉이 가능하다. 10년차 이상 팀장급은 6,000만~9,000만 원 이상의 연봉을 받는 경우도 많다.[2]","source":"워크넷 직업정보, 사람인 직종별 연봉 보고서(2024)"},"overviewProspect":{"main":"디지털 미디어 소비 증가와 데이터 기반 마케팅 확산으로 디지털 마케팅 전문가 수요는 강하게 성장하고 있다.[1] AI 기반 마케팅 도구의 도입으로 단순 콘텐츠 제작 업무는 자동화되는 추세이나, 전략 기획과 크리에이티브 방향 설정은 인간 전문가의 역할이 여전히 중요하다.[2]","source":"한국광고총연합회, 한국고용정보원(2024)"},"trivia":"전 세계 광고 시장 규모는 2024년 기준 약 1조 달러를 넘어섰으며, 디지털 광고가 전체의 70% 이상을 차지하게 됐다.[1] 국내 최초의 TV 광고는 1956년 부라보 아이스크림 광고로 알려져 있으며, 이후 대한민국 광고 산업은 연간 15조 원 이상 규모로 성장했다.[2] 브랜드 친숙도를 높이기 위해 반복 노출이 중요하다는 이론(단순 노출 효과)은 심리학자 로버트 자이언스가 증명했으며, 현대 광고 전략의 기초 이론 중 하나이다.[3]","detailWlb":{"wlb":"보통이하","social":"높음","wlbDetail":"캠페인 론칭 전후로 야근이 집중되고, 클라이언트 요구에 즉각 대응해야 하는 압박이 크다.[4] 광고대행사 특성상 납기 중심의 업무 강도가 높으며, 번아웃 비율이 업계 내에서 높은 편이다.","socialDetail":"창의적 아이디어로 사회에 영향을 미치는 직업으로 인정받으며,[5] 성공적인 캠페인은 개인 경력의 강력한 포트폴리오가 된다. 다양한 산업의 클라이언트와 협업해 폭넓은 네트워크를 쌓을 수 있다."},"detailReady":{"curriculum":["광고홍보학과·경영학과·언론정보학과 관련 전공 이수","디지털 마케팅 자격(Google Analytics 인증, Meta Blueprint 등) 취득","광고공모전(클리오 광고제, 칸 라이언즈 학생 부문 등) 참가 및 수상 경험 축적"],"recruit":["제일기획·이노션·HS애드 등 종합 광고대행사 공채 지원","기업 마케팅팀·홍보팀 공채 또는 경력직 지원","스타트업 그로스 마케터·퍼포먼스 마케터 포지션 지원"],"training":["브랜드 매니저·마케팅 팀장 승진을 위한 실적 포트폴리오 구축","MBA 취득으로 마케팅 전략 직무 경쟁력 강화","데이터 분석(SQL, Python) 학습으로 데이터 드리븐 마케터로 전환"]},"sidebarJobs":["광고기획자","마케팅전문가","카피라이터","콘텐츠마케터","퍼포먼스마케터","시장조사분석가"],"sidebarMajors":["광고·홍보학과","경영학과","마케팅경영과","경영정보학과"],"sidebarCerts":["Google Analytics 인증","Meta Blueprint 인증","사회조사분석사 2급","디지털마케팅전문가","ACA(Adobe Certified Associate)"],"heroTags":["마케팅전문가","광고홍보 취업","디지털마케터","브랜드 마케팅","광고기획자"],"youtubeLinks":[],"_sources":{"way":[{"id":1,"text":"커리어넷 직업백과 – 광고·홍보·마케팅전문가","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=104"},{"id":2,"text":"한국광고총연합회 – 광고인 진로 가이드","url":"https://www.kaa.or.kr"},{"id":3,"text":"워크넷 직업정보 – 광고마케팅전문가","url":"https://www.work.go.kr/seekWantedMain.do"}],"overviewSalary.sal":[{"id":1,"text":"워크넷 직업정보 급여 통계(2024)","url":"https://www.work.go.kr/seekWantedMain.do"},{"id":2,"text":"사람인 직종별 연봉 리포트(2024)","url":"https://www.saramin.co.kr"}],"overviewProspect.main":[{"id":1,"text":"한국광고총연합회 광고 산업 통계(2024)","url":"https://www.kaa.or.kr"},{"id":2,"text":"한국고용정보원 2024 직업전망","url":"https://www.keis.or.kr/user/extra/main/2073/publication/publicationList/jsp/LayOutPage.do"}],"trivia":[{"id":1,"text":"세계 광고 시장 규모 – 한국광고총연합회(2024)","url":"https://www.kaa.or.kr"},{"id":2,"text":"한국 광고 역사 – 한국광고단체연합회","url":"https://www.kaa.or.kr"},{"id":3,"text":"단순 노출 효과(자이언스 효과) – 커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=104"}],"detailWlb.wlbDetail":[{"id":4,"text":"워크넷 직업정보 – 근무환경","url":"https://www.work.go.kr/seekWantedMain.do"}],"detailWlb.socialDetail":[{"id":5,"text":"커리어넷 직업백과 – 직업 만족도","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=104"}]}}' WHERE id = '1765283414312245';